#include<bits/stdc++.h>
using namespace std;
struct edge
{
    long long to,val,nxt;
}e[200010],e1[200010];
long long head[200010],head1[200010],tot=1,tot1;
long long n,m,s,t,dis[200010],now[200010];
void add1(long long u,long long v,long long w)
{
    e[++tot]=(edge){v,w,head[u]};
    head[u]=tot;
}
void add(long long u,long long v,long long w)
{
    add1(u,v,w);
    add1(v,u,0);
}
bool bfs()
{
    for(long long i=0;i<=t;i++)
    {
        dis[i]=0;
    }
    dis[s]=1;
    queue<long long> q;
    q.push(s);
    while(!q.empty())
    {
        long long t=q.front();
        q.pop();
        for(long long i=head[t];i;i=e[i].nxt)
        {
            long long v=e[i].to,val=e[i].val;
            if(dis[v]==0&&val)
            {
                dis[v]=dis[t]+1;
                q.push(v);
                if(v==::t)
                {
                    return true;
                }
            }
        }
    }
    return false;
}
long long x[200010],y[200010],deg[200010],c[200010],d[200010];
long long dfs(long long x,long long flow)
{
    if(x==t||flow==0)
    {
        return flow;
    }
    long long sum=0;
    for(long long i=now[x];i;i=e[i].nxt)
    {
        now[x]=i;
        long long v=e[i].to,val=e[i].val;
        if(dis[v]==dis[x]+1&&val)
        {
            long long tmp=dfs(v,min(flow,val));
            e[i].val-=tmp;
            e[i^1].val+=tmp;
            sum+=tmp;
            flow-=tmp;
            if(flow==0)
            {
                break;
            }
        }
    }
    if(sum==0)
    {
        dis[x]=0;
    }
    return sum;
}
long long dinic()
{
    long long ans=0;
    while(bfs())
    {
        for(long long i=0;i<=t;i++)
        {
            now[i]=head[i];
        }
        ans+=dfs(s,1e9);
    }
    return ans;
}
vector<pair<long long,long long>> mp[200010];
bool check(int mid)
{
    memcpy(head,head1,sizeof(head));
    memcpy(e,e1,sizeof(e));
    tot=tot1;
    for(int i=1;i<=m;i++)
    {
        if(c[i]>mid&&d[i]>mid)
        {
            return false;
        }
        if(c[i]<=mid)
        {
            add(i+n,x[i],1);
        }
        if(d[i]<=mid)
        {
            add(i+n,y[i],1);
        }
    }
    return dinic()==m;
}
vector<int> ans;
void dfs(int x)
{
    while(!mp[x].empty())
    {
        auto i=mp[x].back();
        mp[x].pop_back();
        dfs(i.first);
        ans.push_back(i.second);
    }
}
int main()
{
    scanf("%lld%lld",&n,&m);
    s=0;
    t=21004;
    for(long long i=1;i<=m;i++)
    {
        scanf("%lld%lld%lld%lld",&x[i],&y[i],&c[i],&d[i]);
        deg[x[i]]++;
        deg[y[i]]++;
        add(s,i+n,1);
    }
    for(long long i=1;i<=n;i++)
    {
        if(deg[i]%2==1)
        {
            printf("NIE");
            return 0;
        }
        add(i,t,deg[i]/2);
    }
    tot1=tot;
    memcpy(e1,e,sizeof(e));
    memcpy(head1,head,sizeof(head));
    int l=1,r=1000,best;
    while(l<=r)
    {
        int mid=(l+r)>>1;
        if(check(mid))
        {
            best=mid;
            r=mid-1;
        }
        else
        {
            l=mid+1;
        }
    }
    printf("%d\n",best);
    check(best);
    for(int i=1;i<=m;i++)
    {
        for(int j=head[i+n];j;j=e[j].nxt)
        {
            int v=e[j].to;
            if(v==x[i]&&e[j].val==0)
            {
                mp[x[i]].push_back({y[i],i});
            }
            if(v==y[i]&&e[j].val==0)
            {
                mp[y[i]].push_back({x[i],i});
            }
        }
    }
    dfs(1);
    reverse(ans.begin(),ans.end());
    for(int i:ans)
    {
        printf("%d ",i);
    }
    return 0;
}
